import{_ as a,o as s,c as n,ai as i}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"Onboarding Wizard (CLI)","description":"","frontmatter":{"summary":"CLI onboarding wizard: guided setup for gateway, workspace, channels, and skills","read_when":["Running or configuring the onboarding wizard","Setting up a new machine"],"title":"Onboarding Wizard (CLI)","sidebarTitle":"Onboarding: CLI"},"headers":[],"relativePath":"start/wizard.md","filePath":"start/wizard.md","lastUpdated":1771906665000}'),t={name:"start/wizard.md"};function o(r,e,l,d,h,c){return s(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="onboarding-wizard-cli" tabindex="-1"><a class="header-anchor" href="#onboarding-wizard-cli">#</a> Onboarding Wizard (CLI)</h1><p>The onboarding wizard is the <strong>recommended</strong> way to set up OpenSoul on macOS, Linux, or Windows (via WSL2; strongly recommended). It configures a local Gateway or a remote Gateway connection, plus channels, skills, and workspace defaults in one guided flow.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> onboard</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p><strong>Info:</strong> Fastest first chat: open the Control UI (no channel setup needed). Run <code>opensoul dashboard</code> and chat in the browser. Docs: <a href="/docs/web/dashboard">Dashboard</a>.</p></blockquote><p>To reconfigure later:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> configure</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><blockquote><p><strong>Note:</strong><code>--json</code> does not imply non-interactive mode. For scripts, use <code>--non-interactive</code>.</p></blockquote><blockquote><p><strong>Tip:</strong> Recommended: set up a Brave Search API key so the agent can use <code>web_search</code> (<code>web_fetch</code> works without a key). Easiest path: <code>opensoul configure --section web</code> which stores <code>tools.web.search.apiKey</code>. Docs: <a href="/docs/tools/web">Web tools</a>.</p></blockquote><h2 id="quickstart-vs-advanced" tabindex="-1"><a class="header-anchor" href="#quickstart-vs-advanced">#</a> QuickStart vs Advanced</h2><p>The wizard starts with <strong>QuickStart</strong> (defaults) vs <strong>Advanced</strong> (full control).</p><h3 id="quickstart-defaults" tabindex="-1"><a class="header-anchor" href="#quickstart-defaults">#</a> QuickStart (defaults)</h3><ul><li>Local gateway (loopback)</li><li>Workspace default (or existing workspace)</li><li>Gateway port <strong>18789</strong></li><li>Gateway auth <strong>Token</strong> (auto‑generated, even on loopback)</li><li>Tailscale exposure <strong>Off</strong></li><li>Telegram + WhatsApp DMs default to <strong>allowlist</strong> (you&#39;ll be prompted for your phone number)</li></ul><h3 id="advanced-full-control" tabindex="-1"><a class="header-anchor" href="#advanced-full-control">#</a> Advanced (full control)</h3><ul><li>Exposes every step (mode, workspace, gateway, channels, daemon, skills).</li></ul><h2 id="what-the-wizard-configures" tabindex="-1"><a class="header-anchor" href="#what-the-wizard-configures">#</a> What the wizard configures</h2><p><strong>Local mode (default)</strong> walks you through these steps:</p><h3 id="_1-model-auth" tabindex="-1"><a class="header-anchor" href="#_1-model-auth">#</a> 1. Model/Auth</h3><ul><li><strong>Anthropic API key (recommended)</strong>: Uses <code>ANTHROPIC_API_KEY</code> or prompts for one, then saves it for the daemon.</li><li><strong>Anthropic OAuth (Claude Code)</strong>: Reuses credentials from Claude Code CLI when available.</li><li><strong>OpenAI / Codex</strong>: OAuth or API key support.</li><li><strong>Other Providers</strong>: Support for Gemini, Z.AI, Vercel AI Gateway, MiniMax, Moonshot (Kimi), and more.</li><li><strong>Auth Profiles</strong>: Credentials are stored in <code>~/.opensoul/agents/&lt;agentId&gt;/agent/auth-profiles.json</code>.</li></ul><h3 id="_2-workspace" tabindex="-1"><a class="header-anchor" href="#_2-workspace">#</a> 2. Workspace</h3><ul><li>Default location: <code>~/.opensoul/workspace</code>.</li><li>Seeds bootstrap files for agent initialization.</li><li>See <a href="/docs/concepts/agent-workspace">Agent Workspace</a> for layout details.</li></ul><h3 id="_3-gateway" tabindex="-1"><a class="header-anchor" href="#_3-gateway">#</a> 3. Gateway</h3><ul><li>Configures port (default 18789), bind address, and auth mode.</li><li><strong>Security Tip</strong>: Keep <strong>Token</strong> auth enabled even on loopback for security.</li><li>Optional Tailscale exposure for remote access.</li></ul><h3 id="_4-channels" tabindex="-1"><a class="header-anchor" href="#_4-channels">#</a> 4. Channels</h3><ul><li>Setup for <a href="/docs/channels/whatsapp">WhatsApp</a>, <a href="/docs/channels/telegram">Telegram</a>, <a href="/docs/channels/discord">Discord</a>, <a href="/docs/channels/googlechat">Google Chat</a>, <a href="/docs/channels/mattermost">Mattermost</a>, <a href="/docs/channels/signal">Signal</a>, and <a href="/docs/channels/imessage">iMessage</a>.</li><li>Configures pairing flow for secure DMs.</li></ul><h3 id="_5-daemon-installation" tabindex="-1"><a class="header-anchor" href="#_5-daemon-installation">#</a> 5. Daemon Installation</h3><ul><li><strong>macOS</strong>: LaunchAgent (requires user session).</li><li><strong>Linux / WSL2</strong>: systemd user unit.</li><li><strong>Lingering</strong>: Tries to enable <code>loginctl enable-linger</code> so the gateway stays up after logout.</li><li><strong>Node vs Bun</strong>: <strong>Node</strong> is recommended for WhatsApp/Telegram stability.</li></ul><h3 id="_6-skills" tabindex="-1"><a class="header-anchor" href="#_6-skills">#</a> 6. Skills</h3><ul><li>Installs recommended skills and checks dependencies.</li><li>Configuration for Node manager (<code>npm</code> or <code>pnpm</code>).</li></ul><h2 id="advanced-management" tabindex="-1"><a class="header-anchor" href="#advanced-management">#</a> Advanced Management</h2><h3 id="add-another-agent" tabindex="-1"><a class="header-anchor" href="#add-another-agent">#</a> Add another agent</h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,31)])])}const u=a(t,[["render",o]]);export{g as __pageData,u as default};
